import os
import sys
import subprocess

try:
    import psycopg2
except ImportError:
    subprocess.check_call([sys.executable, '-m', 'pip', 'install', 'psycopg2-binary'])
    import psycopg2


DB_CONFIG = {
    "host": "172.17.0.1",
    "port": "5432",
    "user": "postgres",
    "password": "password",
    "dbname": "postgres"
}


def run_query(target):
    # If target is a valid file path, read SQL from file; otherwise treat as raw SQL
    if isinstance(target, str) and os.path.isfile(target):
        with open(target, 'r') as f:
            sql = f.read()
    else:
        sql = target

    conn = psycopg2.connect(**DB_CONFIG)
    conn.autocommit = True
    try:
        cur = conn.cursor()
        try:
            cur.execute(sql)

            if cur.description is not None:
                columns = [desc[0] for desc in cur.description]
                rows = cur.fetchall()
                print(" | ".join(columns))
                for row in rows:
                    print(" | ".join("" if v is None else str(v) for v in row))
            else:
                print("Query executed successfully.")
        finally:
            cur.close()
    finally:
        conn.close()


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Error: missing argument. Usage: python run_db.py <sql-or-path>", file=sys.stderr)
        sys.exit(1)
    try:
        run_query(sys.argv[1])
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)
